sub extract_metadata {
    my ($pdf_file) = @_;

    my $pdf = PDF::API2->open($pdf_file);

    # Extract metadata
    my $info = $pdf->info;
    my $date = $info->get('CreationDate');
    my $author = $info->get('Author');

    return ($date, $author);
}

# Function to extract table information from PDF
sub extract_table {
    my ($pdf_file) = @_;

    my $pdf = PDF::API2->open($pdf_file);

    # Read all pages
    my @pages = $pdf->pages;
    my @table_data;

    foreach my $page (@pages) {
        # Extract text from the page
        my $text = $page->text;
        my @lines = split /\n/, $text;

        foreach my $line (@lines) {
            # Check for table-like structure
            if ($line =~ /\|/) {
                push @table_data, split /\|/, $line;
            }
        }
    }

    return @table_data;
}

